1	{% extends "base.html" %}
2	{% block title %}Confirm Appointment — MeridianCare{% endblock %}
3	{% block content %}
4	<div class="card auth-container">
5	    <div class="auth-card card">
6	        <h2>Confirm Appointment</h2>
7	        <p><strong>Date:</strong> {{ slot.date }}</p>
8	        <p><strong>Time:</strong> {{ slot.start_time.strftime('%H:%M') }} — {{ slot.end_time.strftime('%H:%M') }}</p>
9	        <p><strong>Clinician:</strong> {{ slot.clinician.user.username }}</p>
10	
11	        {% if remaining_seconds > 0 %}
12	        <div class="alert alert-warning" id="hold-timer">
13	            Hold expires in <span id="countdown">{{ remaining_seconds }}</span> seconds
14	        </div>
15	        <script>
16	        (function(){
17	            var r={{ remaining_seconds }};
18	            var el=document.getElementById('countdown');
19	            setInterval(function(){
20	                r--;
21	                if(r<=0){el.textContent='0';document.getElementById('hold-timer').innerHTML='Hold expired. Please try again.';}
22	                else{var m=Math.floor(r/60),s=r%60;el.textContent=(m>0?m+'m ':'')+s+'s';}
23	            },1000);
24	        })();
25	        </script>
26	        {% endif %}
27	
28	        {% set _confirm_action = url_for('schedule.confirm', reservation_id=reservation.id) %}
29	        <form method="POST" action="{{ _confirm_action }}" style="margin-top:1rem;">
30	            <input type="hidden" name="csrf_token" value="{{ csrf_token() }}">
31	            {{ antireplay_inputs("POST", _confirm_action) }}
32	            <button type="submit" class="btn btn-primary btn-block">Confirm Booking</button>
33	        </form>
34	        {% set _cancel_action = url_for('schedule.cancel', reservation_id=reservation.id) %}
35	        <form method="POST" action="{{ _cancel_action }}" style="margin-top:0.5rem;">
36	            <input type="hidden" name="csrf_token" value="{{ csrf_token() }}">
37	            {{ antireplay_inputs("POST", _cancel_action) }}
38	            <button type="submit" class="btn btn-secondary btn-block">Cancel</button>
39	        </form>
40	    </div>
41	</div>
42	{% endblock %}
