1	{% extends "base.html" %}
2	{% block title %}Confirm Appointment — MeridianCare{% endblock %}
3	{% block content %}
4	<div class="card auth-container">
5	    <div class="auth-card card">
6	        <h2>Confirm Appointment</h2>
7	        <p><strong>Date:</strong> {{ slot.date }}</p>
8	        <p><strong>Time:</strong> {{ slot.start_time.strftime('%H:%M') }} — {{ slot.end_time.strftime('%H:%M') }}</p>
9	        <p><strong>Clinician:</strong> {{ slot.clinician.user.username }}</p>
10	
11	        {% if remaining_seconds > 0 %}
12	        <div class="alert alert-warning" id="hold-timer">
13	            Hold expires in <span id="countdown" data-seconds="{{ remaining_seconds }}">{{ remaining_seconds }}</span> seconds
14	        </div>
15	        {% endif %}
16	
17	        {% set _confirm_action = url_for('schedule.confirm', reservation_id=reservation.id) %}
18	        <form method="POST" action="{{ _confirm_action }}" style="margin-top:1rem;">
19	            <input type="hidden" name="csrf_token" value="{{ csrf_token() }}">
20	            {{ antireplay_inputs("POST", _confirm_action) }}
21	            <button type="submit" class="btn btn-primary btn-block">Confirm Booking</button>
22	        </form>
23	        {% set _cancel_action = url_for('schedule.cancel', reservation_id=reservation.id) %}
24	        <form method="POST" action="{{ _cancel_action }}" style="margin-top:0.5rem;">
25	            <input type="hidden" name="csrf_token" value="{{ csrf_token() }}">
26	            {{ antireplay_inputs("POST", _cancel_action) }}
27	            <button type="submit" class="btn btn-secondary btn-block">Cancel</button>
28	        </form>
29	    </div>
30	</div>
31	{% endblock %}
